/* upsolve with Dukkha */
#include <stdio.h>

#define N	2000
#define MD	998244353

int ch[1 + N][1 + N];

void init(int n) {
	int i, j;

	ch[0][0] = 1;
	for (i = 1; i <= n; i++) {
		ch[i][0] = 1;
		for (j = 1; j <= i; j++)
			ch[i][j] = (ch[i - 1][j] + ch[i - 1][j - 1]) % MD;
	}
}

long long power(int a, int k) {
	long long p;

	if (k == 0)
		return 1;
	p = power(a, k / 2);
	p = p * p % MD;
	if (k % 2)
		p = p * a % MD;
	return p;
}

int main() {
	static long long pp[1 + N + N], qq[1 + N + N], aa[1 + N + N];
	int n, k, l, i, j;
	long long inv2, a;

	scanf("%d%d%d", &n, &k, &l);
	init(n);
	pp[n] = power(2, n);
	for (i = 0; i < n; i++)
		for (j = n + n; j > 0; j--)
			pp[j] = (pp[j] - pp[j - 1]) % MD;
	for (j = 0; j <= n + n; j++)
		aa[j] = pp[j];
	inv2 = (MD + 1) / 2;
	for (i = 1; i <= n - k; i++) {
		/* qq := pp / p, where p = 2x (1 - x) */
		/* divide by 2x */
		for (j = 1; j < n + n; j++)
			qq[j] = pp[j + 1] * inv2 % MD;
		qq[n + n] = 0;
		/* divide by 1 - x is multiply by 1 + x + x^2 + x^3 + ... */
		for (j = 1; j <= n + n; j++)
			qq[j] = (qq[j] + qq[j - 1]) % MD;
		/* pp := pp * (1 - p) / p = pp / p - pp = qq - pp */
		for (j = 0; j <= n + n; j++)
			pp[j] = (qq[j] - pp[j]) % MD;
		a = ch[n][i];
		for (j = 0; j <= n + n; j++)
			aa[j] = (aa[j] + a * pp[j]) % MD;
	}
	/* integrate x^i to x^{i + 1} / (i + 1) */
	a = 0;
	for (i = 0; i <= n + n; i++)
		a = (a + aa[i] * power(i + 1, MD - 2)) % MD;
	a = (a * l % MD + MD) % MD;
	printf("%lld\n", a);
	return 0;
}

