/// FFT (in-place, verified as NTT only)
/// R: Ring + Copy
/// Verified by: https://codeforces.com/contest/1096/submission/47672373
mod fft {
    use std::ops::*;
    /// n should be a power of 2. zeta is a primitive n-th root of unity.
    /// one is unity
    /// Note that the result should be multiplied by 1/sqrt(n).
    pub fn transform<R>(f: &mut [R], zeta: R, one: R)
        where R: Copy +
        Add<Output = R> +
        Sub<Output = R> +
        Mul<Output = R> {
        let n = f.len();
        assert!(n.is_power_of_two());
        {
            let mut i = 0;
            for j in 1 .. n - 1 {
                let mut k = n >> 1;
                loop {
                    i ^= k;
                    if k <= i { break; }
                    k >>= 1;
                }
                if j < i { f.swap(i, j); }
            }
        }
        let mut zetapow = Vec::new();
        {
            let mut m = 1;
            let mut cur = zeta;
            while m < n {
                zetapow.push(cur);
                cur = cur * cur;
                m *= 2;
            }
        }
        let mut m = 1;
        while m < n {
            let base = zetapow.pop().unwrap();
            let mut r = 0;
            while r < n {
                let mut w = one;
                for s in r .. r + m {
                    let u = f[s];
                    let d = f[s + m] * w;
                    f[s] = u + d;
                    f[s + m] = u - d;
                    w = w * base;
                }
                r += 2 * m;
            }
            m *= 2;
        }
    }
}

use fft::*;

// Depends on ModInt.rs
fn fact_init(w: usize) -> (Vec<ModInt>, Vec<ModInt>) {
    let mut fac = vec![ModInt::new(1); w];
    let mut invfac = vec![0.into(); w];
    for i in 1 .. w {
        fac[i] = fac[i - 1] * i as i64;
    }
    invfac[w - 1] = fac[w - 1].inv();
    for i in (0 .. w - 1).rev() {
        invfac[i] = invfac[i + 1] * (i as i64 + 1);
    }
    (fac, invfac)
}

fn solve() {
    let out = std::io::stdout();
    let mut out = BufWriter::new(out.lock());
    macro_rules! puts {
        ($($format:tt)*) => (write!(out,$($format)*).unwrap());
    }
    input! {
        n: usize,
        k: usize,
        l: i64,
    }
    const N: usize = 4096;
    let (fac, invfac) = fact_init(N);

    let mut p = vec![ModInt::new(0); N];
    let mut q = vec![ModInt::new(0); N];
    p[1] = ModInt::new(2);
    p[2] = -ModInt::new(2);
    q[0] = ModInt::new(1);
    q[1] = -ModInt::new(2);
    q[2] = ModInt::new(2);

    let zeta = ModInt::new(3).pow((MOD - 1) / N as i64);
    transform(&mut p, zeta, ModInt::new(1));
    transform(&mut q, zeta, ModInt::new(1));

    let mut ans = vec![ModInt::new(0); N];
    let mut coef = vec![ModInt::new(0); N];
    for i in k..n + 1 {
        coef[i] = fac[n] * invfac[n - i] * invfac[i];
    }
    for j in 0..N {
        let mut pp = p[j].pow(k as i64);
        let mut qp = q[j].pow((n - k) as i64);
        let mut qinv = q[j].inv();
        for i in k..n + 1 {
            let coef = coef[i];
            ans[j] += pp * qp * coef;
            pp *= p[j];
            qp *= qinv;
        }
    }
    transform(&mut ans, zeta.inv(), ModInt::new(1));
    // eprintln!("ans = {:?}", &ans[0..10]);
    let mut tot = ModInt::new(0);
    for i in 0..2 * n + 1 {
        tot += ans[i] * ModInt::new((i + 1) as i64).inv();
    }
    tot *= ModInt::new(N as i64).inv();
    puts!("{}\n", tot * l);
}

fn main() {
    // In order to avoid potential stack overflow, spawn a new thread.
    let stack_size = 104_857_600; // 100 MB
    let thd = std::thread::Builder::new().stack_size(stack_size);
    thd.spawn(|| solve()).unwrap().join().unwrap();
}
